"use client";

import Link from "next/link";
import { useEffect, useMemo, useState } from "react";
import { Pencil, Trash2, Plus } from "lucide-react";

type Usulan = {
  id: string;
  esl: string;
  jabatan: string;
  nama: string;
  pktGol: string;
  nrpNip: string;
  createdAt: string;
  updatedAt?: string;
};

const STORAGE_KEY = "bnn_usulan_v1";

function loadUsulan(): Usulan[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return raw ? (JSON.parse(raw) as Usulan[]) : [];
  } catch {
    return [];
  }
}

function saveUsulan(next: Usulan[]) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(next));
}

export default function DaftarUsulanPage() {
  const [rows, setRows] = useState<Usulan[]>([]);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [draft, setDraft] = useState<Partial<Usulan>>({});

  useEffect(() => {
    setRows(loadUsulan());
  }, []);

  const data = useMemo(() => rows, [rows]);

  function onDelete(id: string) {
    const ok = confirm("Yakin mau hapus data ini?");
    if (!ok) return;

    const next = rows.filter((r) => r.id !== id);
    setRows(next);
    saveUsulan(next);
  }

  function startEdit(row: Usulan) {
    setEditingId(row.id);
    setDraft({ ...row });
  }

  function cancelEdit() {
    setEditingId(null);
    setDraft({});
  }

  function applyEdit() {
    if (!editingId) return;

    const now = new Date().toISOString();
    const next = rows.map((r) => {
      if (r.id !== editingId) return r;
      return {
        ...r,
        esl: String(draft.esl ?? "").trim(),
        jabatan: String(draft.jabatan ?? "").trim(),
        nama: String(draft.nama ?? "").trim(),
        pktGol: String(draft.pktGol ?? "").trim(),
        nrpNip: String(draft.nrpNip ?? "").trim(),
        updatedAt: now,
      };
    });

    setRows(next);
    saveUsulan(next);
    cancelEdit();
  }

  return (
    <div className="px-2 py-2">
      <div className="mx-auto w-full max-w-[1100px] rounded-md bg-white shadow-[0_14px_40px_rgba(0,0,0,0.18)] ring-1 ring-black/5">
        <div className="p-10">
          {/* Header */}
          <div className="flex items-start justify-between">
            <div className="text-[11px] font-semibold text-zinc-900">
              <div>BADAN NARKOTIKA NASIONAL</div>
              <div>REPUBLIK INDONESIA</div>
              <div className="mt-2 h-[2px] w-[190px] bg-zinc-700/70" />
            </div>

            <div className="pt-2 text-center">
              <div className="text-sm font-bold tracking-wide text-zinc-900">
                DAFTAR USULAN
              </div>
            </div>

            <div className="flex w-[220px] justify-end">
              <Link
                href="/usulan/input_usulan"
                className="inline-flex items-center gap-2 rounded-md bg-[#123473] px-3 py-2 text-xs font-semibold text-white hover:brightness-110"
              >
                <Plus size={16} />
                Input Usulan
              </Link>
            </div>
          </div>

          {/* Table */}
          <div className="mt-8 overflow-x-auto">
            <table className="w-full border border-zinc-700 text-[12px] text-zinc-900">
              <thead>
                <tr className="bg-zinc-200/80">
                  <Th className="w-[60px] text-center">NO</Th>
                  <Th className="w-[90px] text-center">ESL</Th>
                  <Th className="w-[220px] text-center">JABATAN</Th>
                  <Th className="w-[260px] text-center">NAMA</Th>
                  <Th className="w-[120px] text-center">PKT/GOL</Th>
                  <Th className="w-[140px] text-center">NRP/NIP</Th>
                  <Th className="w-[160px] text-center">Aksi</Th>
                </tr>
              </thead>

              <tbody>
                {data.length === 0 ? (
                  <tr className="border-t border-zinc-700">
                    <Td colSpan={7} className="py-10 text-center text-zinc-500">
                      Belum ada data. Silakan input usulan dulu.
                    </Td>
                  </tr>
                ) : (
                  data.map((r, idx) => {
                    const isEdit = editingId === r.id;

                    return (
                      <tr key={r.id} className="border-t border-zinc-700">
                        <Td className="text-center">{idx + 1}.</Td>

                        <Td>{isEdit ? <CellInput value={draft.esl ?? ""} onChange={(v) => setDraft((p) => ({ ...p, esl: v }))} /> : r.esl}</Td>
                        <Td>{isEdit ? <CellInput value={draft.jabatan ?? ""} onChange={(v) => setDraft((p) => ({ ...p, jabatan: v }))} /> : r.jabatan}</Td>
                        <Td>{isEdit ? <CellInput value={draft.nama ?? ""} onChange={(v) => setDraft((p) => ({ ...p, nama: v }))} /> : r.nama}</Td>
                        <Td>{isEdit ? <CellInput value={draft.pktGol ?? ""} onChange={(v) => setDraft((p) => ({ ...p, pktGol: v }))} /> : r.pktGol}</Td>
                        <Td>{isEdit ? <CellInput value={draft.nrpNip ?? ""} onChange={(v) => setDraft((p) => ({ ...p, nrpNip: v }))} /> : r.nrpNip}</Td>

                        <Td>
                          <div className="flex items-center justify-center gap-2">
                            {!isEdit ? (
                              <>
                                <button
                                  type="button"
                                  className="inline-flex h-9 w-9 items-center justify-center rounded-md border border-[#123473]/40 bg-white text-[#123473] shadow-sm transition hover:bg-[#123473]/5 active:scale-[0.98]"
                                  title="Edit"
                                  onClick={() => startEdit(r)}
                                >
                                  <Pencil size={18} />
                                </button>

                                <button
                                  type="button"
                                  className="inline-flex h-9 w-9 items-center justify-center rounded-md border border-red-500/40 bg-white text-red-600 shadow-sm transition hover:bg-red-50 active:scale-[0.98]"
                                  title="Hapus"
                                  onClick={() => onDelete(r.id)}
                                >
                                  <Trash2 size={18} />
                                </button>
                              </>
                            ) : (
                              <>
                                <button
                                  type="button"
                                  className="rounded-md bg-[#123473] px-3 py-2 text-xs font-semibold text-white hover:brightness-110"
                                  onClick={applyEdit}
                                >
                                  Simpan
                                </button>
                                <button
                                  type="button"
                                  className="rounded-md border border-zinc-300 px-3 py-2 text-xs font-semibold text-zinc-700 hover:bg-zinc-50"
                                  onClick={cancelEdit}
                                >
                                  Batal
                                </button>
                              </>
                            )}
                          </div>
                        </Td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>

          {/* Footer kiri */}
          <div className="mt-10 text-[10px] text-zinc-700">
            <div>Biro SDM Aparatur dan Organisasi</div>
            <div>Sekretariat Utama BNN 2026</div>
          </div>
        </div>
      </div>
    </div>
  );
}

function Th({
  children,
  className = "",
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <th className={["border border-zinc-700 px-3 py-2 font-bold", className].join(" ")}>
      {children}
    </th>
  );
}

function Td({
  children,
  className = "",
  colSpan,
}: {
  children: React.ReactNode;
  className?: string;
  colSpan?: number;
}) {
  return (
    <td
      colSpan={colSpan}
      className={["border border-zinc-700 px-3 py-3", className].join(" ")}
    >
      {children}
    </td>
  );
}

function CellInput({
  value,
  onChange,
}: {
  value: string;
  onChange: (v: string) => void;
}) {
  return (
    <input
      value={value}
      onChange={(e) => onChange(e.target.value)}
      className="h-9 w-full rounded-md border border-zinc-300 bg-white px-2 text-[12px] outline-none focus:border-[#123473] focus:ring-2 focus:ring-[#123473]/20"
    />
  );
}
